import{_ as a,c as i,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Auditoría de diseño: 100 prácticas | Agent Skills","description":"Aprende a aplicar 100 mejores prácticas de diseño web. Verifica accesibilidad WCAG, rendimiento de animaciones y modo oscuro, mejorando la calidad de interfaz.","frontmatter":{"title":"Auditoría de diseño: 100 prácticas | Agent Skills","sidebarTitle":"Auditoría de diseño","subtitle":"Auditoría de guías de diseño de interfaz web","description":"Aprende a aplicar 100 mejores prácticas de diseño web. Verifica accesibilidad WCAG, rendimiento de animaciones y modo oscuro, mejorando la calidad de interfaz.","tags":["Accesibilidad","UX","Revisión de código","Diseño web"],"prerequisite":["start-getting-started"]},"headers":[],"relativePath":"es/vercel-labs/agent-skills/platforms/web-design-guidelines/index.md","filePath":"es/vercel-labs/agent-skills/platforms/web-design-guidelines/index.md"}'),s={name:"es/vercel-labs/agent-skills/platforms/web-design-guidelines/index.md"};function d(t,e,n,l,c,u){return r(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="auditoria-de-guias-de-diseno-de-interfaz-web" tabindex="-1">Auditoría de guías de diseño de interfaz web <a class="header-anchor" href="#auditoria-de-guias-de-diseno-de-interfaz-web" aria-label="Permalink to &quot;Auditoría de guías de diseño de interfaz web&quot;">​</a></h1><h2 id="lo-que-podras-hacer-al-terminar" tabindex="-1">Lo que podrás hacer al terminar <a class="header-anchor" href="#lo-que-podras-hacer-al-terminar" aria-label="Permalink to &quot;Lo que podrás hacer al terminar&quot;">​</a></h2><ul><li>🎯 Hacer que la IA audite automáticamente el código de UI, descubriendo problemas de accesibilidad, rendimiento y UX</li><li>♿ Aplicar mejores prácticas de accesibilidad web (WCAG), mejorando la accesibilidad del sitio</li><li>⚡ Optimizar el rendimiento de animaciones y la carga de imágenes, mejorando la experiencia de usuario</li><li>🎨 Asegurar la implementación correcta del modo oscuro y el diseño responsivo</li><li>🔍 Reparar anti-patrones comunes de UI (como <code>transition: all</code>, falta de aria-labels, etc.)</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p>Escribiste componentes de UI, pero siempre sientes que algo no está bien:</p><ul><li>El sitio pasa las pruebas funcionales, pero no sabes si cumple con los estándares de accesibilidad</li><li>El rendimiento de las animaciones es malo, los usuarios reportan que la página se siente lenta</li><li>Algunos elementos no se ven claramente en modo oscuro</li><li>El código generado por la IA funciona, pero le faltan aria-labels necesarios o HTML semántico</li><li>Cada revisión de código requiere verificar manualmente 17 categorías de reglas, baja eficiencia</li><li>No sabes cuándo usar propiedades CSS como <code>prefers-reduced-motion</code>, <code>tabular-nums</code></li></ul><h2 id="idea-central" tabindex="-1">Idea central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea central&quot;">​</a></h2><p>Las guías de diseño de interfaz web cubren <strong>17 categorías</strong>, agrupadas en tres bloques principales por prioridad:</p><table tabindex="0"><thead><tr><th>Bloque de categorías</th><th>Enfoque</th><th>Beneficio típico</th></tr></thead><tbody><tr><td><strong>Accesibilidad</strong></td><td>Asegurar que todos los usuarios puedan usar (incluyendo lectores de pantalla, usuarios de teclado)</td><td>Cumplir con estándares WCAG, ampliar base de usuarios</td></tr><tr><td><strong>Rendimiento y UX</strong></td><td>Optimizar velocidad de carga, fluidez de animaciones, experiencia de interacción</td><td>Mejorar retención de usuarios, reducir tasa de rebote</td></tr><tr><td><strong>Integridad y detalles</strong></td><td>Modo oscuro, diseño responsivo, validación de formularios, manejo de errores</td><td>Reducir quejas de usuarios, mejorar imagen de marca</td></tr></tbody></table><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo usar esta técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo usar esta técnica&quot;">​</a></h2><p>Usar la habilidad de guías de diseño web en escenarios típicos:</p><ul><li>❌ <strong>No aplicable</strong>: lógica puramente de back-end, páginas de prototipo simples (sin interacción de usuario)</li><li>✅ <strong>Aplicable</strong>: <ul><li>Escribir nuevos componentes de UI (botones, formularios, tarjetas, etc.)</li><li>Implementar funciones de interacción (modales, menús desplegables, arrastrar y soltar, etc.)</li><li>Revisar o refactorizar componentes de UI</li><li>Verificación de calidad de UI antes del lanzamiento</li><li>Reparar problemas de accesibilidad o rendimiento reportados por usuarios</li></ul></li></ul><h2 id="proximos-pasos" tabindex="-1">Próximos pasos <a class="header-anchor" href="#proximos-pasos" aria-label="Permalink to &quot;Próximos pasos&quot;">​</a></h2><p>Ver <a href="./../vercel-deploy/">Implementación con un clic en Vercel</a> para aprender a usar funciones de implementación.</p>',14)])])}const b=a(s,[["render",d]]);export{m as __pageData,b as default};
